import { NextResponse } from "next/server";

export async function GET(req: Request) {
  const { searchParams } = new URL(req.url);
  const q = searchParams.get("q") ?? "What can I bring to my dorm?";

  const mock = {
    question: q,
    answer:
      "Mock answer: This UI shows the answer on the left and referenced sources on the right. Later, the backend will return real results with citations.",
    sources: [
      {
        title: "University Residences Guidelines",
        url: "https://www.housing.purdue.edu/",
        snippet:
          "Mock snippet: Residence hall guidelines and safety rules. This is placeholder content for the prototype.",
      },
      {
        title: "Student Policies & Handbook",
        url: "https://www.purdue.edu/",
        snippet:
          "Mock snippet: Official policy pages and student resources. Placeholder source card to test layout.",
      },
      {
        title: "Example FAQ / Resource",
        url: "https://www.purdue.edu/",
        snippet:
          "Mock snippet: Another sample citation. Your real system will provide accurate sources and snippets.",
      },
    ],
  };

  return NextResponse.json(mock);
}